#include <stdio.h>

int main() {
    FILE *dat = fopen("broj.dat", "rb");
    if (dat == NULL) {
        printf("Greska pri otvaranju datoteke.\n");
        return 1;
    }

    double podatak;

    fread(&podatak, sizeof(double), 1, dat);

    fclose(dat);

    printf("Ucitani podatak: %.2f\n", podatak);

    return 0;
}
